Cool, well I paste code which I use to hide this annoying error message from console
for people who are too tired to see this error message :-)

``settings.py``::

    import logging
    class NoMessageFailuresFilter(logging.Filter):
        def filter(self, record):
            if record.exc_info:
                from django.contrib.messages.api import MessageFailure
                exception = record.exc_info[1]
                if isinstance(exception, MessageFailure):
                    # I DON'T WANT TO SEE ANNOYING MESSAGEFAILURE EXCEPTION!!!
                    return False
            return True
    LOGGING = {
        'version': 1,
        'disable_existing_loggers': True,
        'formatters': {
            'verbose': {
                'format': '%(name)s %(levelname)s %(asctime)s %(module)s %(process)d %(thread)d %(message)s'
            },
            'simple': {
                'format': '%(levelname)s %(message)s'
            },
        },
        'handlers': {
            'null': {
                'level': 'DEBUG',
                'class':'django.utils.log.NullHandler',
            },
            'console': {
                'level': 'DEBUG',
                'class': 'logging.StreamHandler',
                'formatter': 'verbose'
            }
        },
        'filters': {
            'no_message_failures': {
                '()': NoMessageFailuresFilter,
            },
        },
        'loggers': {
            'django.request': {
                'handlers': ['console'],
                'level': 'ERROR',
                'propagate': False,
                # stop MessageFailure !
                'filters': ['no_message_failures'],
            },
            '': {
                'level': 'ERROR',
                'handlers': ['console'],
            },
        },
    }

